import subprocess
import json

def execute_docker_sandbox(code: str, timeout: int = 15) -> dict:
    try:
        proc = subprocess.run(
            [
                "docker", "run", "--rm",
                "--network", "none",
                "--memory", "128m",
                "--memory-swap", "128m",
                "--cpu-quota", "50000",       # 50% of 1 CPU
                "--pids-limit", "32",         # max 32 processes
                "--read-only",
                "--tmpfs", "/tmp:size=16m,noexec",
                "--cap-drop", "ALL",          # drop all Linux capabilities
                "--security-opt", "no-new-privileges",
                "--security-opt", "seccomp=/etc/docker/seccomp/default.json",
                "python-sandbox",
            ],
            input=code,
            capture_output=True,
            text=True,
            timeout=timeout + 5,
        )
        if proc.stdout:
            try:
                return json.loads(proc.stdout)
            except json.JSONDecodeError:
                return {"stdout": proc.stdout[:8192], "error": None}
        return {"stdout": "", "error": proc.stderr[:2048] or "Container exited with no output"}
    except subprocess.TimeoutExpired:
        return {"stdout": "", "error": f"Container timed out after {timeout}s"}
    except FileNotFoundError:
        return {"stdout": "", "error": "Docker not available"}
